def get_max_count(s, t):
    s_count = s.count(t)
    if s_count == 0:
        return 0
    max_count = s_count
    for i in range(len(s)):
        if s[i] != '?':
            continue
        s_copy = s[:i] + '?' + s[i + 1:]
        s_count = s_copy.count(t)
        if s_count > max_count:
            max_count = s_count
    return max_count


def main():
    s = input().strip()
    t = input().strip()
    print(get_max_count(s, t))


if __name__ == '__main__':
    main()
